105	func SetMasterWorktree(ctx context.Context, projectRoot, masterPath string) error {
106		if ctx == nil {
107			ctx = context.Background()
108		}
109	
110		root := Path(ctx, projectRoot)
111		return withBootstrapLock(root, func() error {
112			registryPath := filepath.Join(root, "worktrees.json")
113			registry, err := readWorktreeRegistry(registryPath)
114			if err != nil {
115				return err
116			}
117	
118			canonicalPath, err := canonicalWorktreePath(masterPath)
119			if err != nil {
120				return err
121			}
122	
123			now := time.Now().UTC().Format(time.RFC3339Nano)
124			hostname, err := os.Hostname()
125			if err != nil || strings.TrimSpace(hostname) == "" {
126				hostname = "unknown"
127			}
128	
129			changed := upsertWorktreeRegistryEntry(&registry, canonicalPath, now, hostname)
130			if registry.Master != canonicalPath {
131				registry.Master = canonicalPath
132				changed = true
133			}
134			if !changed {
135				return nil
136			}
137			return writeWorktreeRegistry(registryPath, registry)
138		})
139	}
