152	func resolveOriginURL(ctx context.Context, projectRoot string) string {
153		if ctx == nil {
154			ctx = context.Background()
155		}
156		out, err := gitpkg.Command(ctx, projectRoot, "remote", "get-url", "origin").Output()
157		if err != nil {
158			return ""
159		}
160		return strings.TrimSpace(string(out))
