163	func parseRemoteProject(remoteURL string) (string, bool) {
164		remoteURL = strings.TrimSpace(remoteURL)
165		if remoteURL == "" {
166			return "", false
167		}
168		if host, repoPath, ok := parseSCPLikeRemote(remoteURL); ok {
169			return filepath.Join(host, repoPath), true
170		}
171		u, err := url.Parse(remoteURL)
172		if err != nil || u.Host == "" {
173			return "", false
174		}
175		repoPath := normalizeRepoPath(u.Path)
176		if repoPath == "" {
177			return "", false
178		}
179		return filepath.Join(u.Host, repoPath), true
180	}
181	
182	func parseSCPLikeRemote(remoteURL string) (host, repoPath string, ok bool) {
183		if strings.Contains(remoteURL, "://") {
184			return "", "", false
185		}
186		at := strings.IndexByte(remoteURL, '@')
187		colon := strings.IndexByte(remoteURL, ':')
188		if at <= 0 || colon <= at+1 {
189			return "", "", false
190		}
191		host = strings.TrimSpace(remoteURL[at+1 : colon])
192		repoPath = normalizeRepoPath(remoteURL[colon+1:])
193		if host == "" || repoPath == "" {
194			return "", "", false
195		}
196		return host, repoPath, true
197	}
