199	func normalizeRepoPath(raw string) string {
200		raw = strings.TrimSpace(raw)
201		raw = strings.Trim(raw, "/")
202		raw = strings.TrimSuffix(raw, ".git")
203		if raw == "" {
204			return ""
205		}
206		parts := strings.FieldsFunc(raw, func(r rune) bool {
207			return r == '/' || r == '\\'
208		})
209		if len(parts) == 0 {
210			return ""
211		}
212		return filepath.Join(parts...)
213	}
