215	func localProjectIdentity(projectRoot string) string {
216		absRoot, err := filepath.Abs(projectRoot)
217		if err != nil {
218			absRoot = filepath.Clean(projectRoot)
219		}
220		base := filepath.Base(absRoot)
221		if base == "." || base == string(filepath.Separator) || base == "" {
222			base = "project"
223		}
224		return filepath.Join("local", base+"-"+shortPathHash(absRoot))
225	}
