248	func bootstrapConventionRoot(ctx context.Context, projectRoot, root string) error {
249		if ctx == nil {
250			ctx = context.Background()
251		}
252		return withBootstrapLock(root, func() error {
253			if err := os.MkdirAll(root, 0o755); err != nil {
254				return err
255			}
256			if err := ensureGitRepo(ctx, root); err != nil {
257				return err
258			}
259			changed, err := ensureWorktreeRegistry(projectRoot, root)
260			if err != nil {
261				return err
262			}
263			if err := ensureHeadCommit(ctx, root, changed); err != nil {
264				return err
265			}
266			return nil
267		})
268	}
