270	func withBootstrapLock(root string, fn func() error) error {
271		lockDir := root + ".bootstrap.lock"
272		if err := os.MkdirAll(filepath.Dir(lockDir), 0o755); err != nil {
273			return err
274		}
275		deadline := time.Now().Add(30 * time.Second)
276		for {
277			err := os.Mkdir(lockDir, 0o755)
278			if err == nil {
279				_ = os.WriteFile(filepath.Join(lockDir, "pid"), []byte(strconv.Itoa(os.Getpid())), 0o644)
280				_ = os.WriteFile(filepath.Join(lockDir, "acquired_at"), []byte(time.Now().UTC().Format(time.RFC3339Nano)), 0o644)
281				defer os.RemoveAll(lockDir)
282				return fn()
283			}
284			if breakStaleBootstrapLock(lockDir) {
285				continue
286			}
287			if time.Now().After(deadline) {
288				return err
289			}
290			time.Sleep(25 * time.Millisecond)
291		}
292	}
293	
294	func breakStaleBootstrapLock(lockDir string) bool {
295		acquiredAt, err := os.ReadFile(filepath.Join(lockDir, "acquired_at"))
296		if err == nil {
297			if ts, parseErr := time.Parse(time.RFC3339Nano, strings.TrimSpace(string(acquiredAt))); parseErr == nil && time.Since(ts) > bootstrapLockStaleAge {
298				_ = os.RemoveAll(lockDir)
299				return true
300			}
301		}
302		return false
303	}
