305	func ensureGitRepo(ctx context.Context, root string) error {
306		if out, err := gitpkg.Command(ctx, root, "rev-parse", "--git-dir").CombinedOutput(); err == nil {
307			_ = out
308			return nil
309		}
310		out, err := gitpkg.Command(ctx, root, "init").CombinedOutput()
311		if err != nil {
312			return newGitError("git init", out, err)
313		}
314		return nil
315	}
