317	func ensureWorktreeRegistry(projectRoot, root string) (bool, error) {
318		worktreePath, err := canonicalWorktreePath(projectRoot)
319		if err != nil {
320			return false, err
321		}
322	
323		registryPath := filepath.Join(root, "worktrees.json")
324		registry, err := readWorktreeRegistry(registryPath)
325		if err != nil {
326			return false, err
327		}
328	
329		now := time.Now().UTC().Format(time.RFC3339Nano)
330		hostname, err := os.Hostname()
331		if err != nil || strings.TrimSpace(hostname) == "" {
332			hostname = "unknown"
333		}
334	
335		changed := upsertWorktreeRegistryEntry(&registry, worktreePath, now, hostname)
336		if registry.Master == "" {
337			registry.Master = worktreePath
338			changed = true
339		}
340		if !changed {
341			return false, nil
342		}
343		return true, writeWorktreeRegistry(registryPath, registry)
344	}
345	
346	func upsertWorktreeRegistryEntry(registry *worktreeRegistry, worktreePath, now, hostname string) bool {
347		for i := range registry.Paths {
348			if registry.Paths[i].Path != worktreePath {
349				continue
350			}
351			changed := false
352			if registry.Paths[i].FirstSeenAt == "" {
353				registry.Paths[i].FirstSeenAt = now
354				changed = true
355			}
356			if registry.Paths[i].LastSeenAt != now {
357				if registry.Paths[i].LastSeenAt == "" {
358					registry.Paths[i].LastSeenAt = registry.Paths[i].FirstSeenAt
359				}
360				if registry.Paths[i].LastSeenAt != now {
361					registry.Paths[i].LastSeenAt = now
362				}
363				changed = true
364			}
365			if registry.Paths[i].Hostname == "" {
366				registry.Paths[i].Hostname = hostname
367				changed = true
368			}
369			return changed
370		}
371	
372		registry.Paths = append(registry.Paths, worktreeRegistryEntry{
373			Path:        worktreePath,
374			FirstSeenAt: now,
375			LastSeenAt:  now,
376			Hostname:    hostname,
377		})
378		return true
379	}
