389	func readWorktreeRegistry(path string) (worktreeRegistry, error) {
390		data, err := os.ReadFile(path)
391		if err != nil {
392			if os.IsNotExist(err) {
393				return worktreeRegistry{}, nil
394			}
395			return worktreeRegistry{}, err
396		}
397		if len(data) == 0 {
398			return worktreeRegistry{}, nil
399		}
400		var registry worktreeRegistry
401		if err := json.Unmarshal(data, &registry); err != nil {
402			return worktreeRegistry{}, err
403		}
404		return registry, nil
405	}
406	
407	func writeWorktreeRegistry(path string, registry worktreeRegistry) error {
408		data, err := json.MarshalIndent(registry, "", "  ")
409		if err != nil {
410			return err
411		}
412		data = append(data, '\n')
413		tmp := path + ".tmp"
414		if err := os.WriteFile(tmp, data, 0o644); err != nil {
415			return err
416		}
417		return os.Rename(tmp, path)
418	}
