420	func ensureHeadCommit(ctx context.Context, root string, stageRegistry bool) error {
421		if headExists(ctx, root) {
422			return nil
423		}
424		if stageRegistry {
425			out, err := gitpkg.Command(ctx, root, "add", "worktrees.json").CombinedOutput()
426			if err != nil {
427				return newGitError("git add worktrees.json", out, err)
428			}
429		}
430		out, err := gitpkg.Command(
431			ctx,
432			root,
433			"-c", "user.name=DDx Bootstrap",
434			"-c", "user.email=ddx-bootstrap@localhost",
435			"-c", "commit.gpgsign=false",
436			"commit", "--allow-empty", "-m", bootstrapCommitMessage,
437		).CombinedOutput()
438		if err != nil {
439			return newGitError("git commit", out, err)
440		}
441		return nil
442	}
