234	func prepareSymlinkTarget(target string, force bool) error {
235		if info, err := os.Lstat(target); err == nil {
236			if info.Mode()&os.ModeSymlink != 0 || force {
237				if err := os.RemoveAll(target); err != nil {
238					return fmt.Errorf("removing existing %s: %w", target, err)
239				}
240				return nil
241			}
242			return fmt.Errorf("%s already exists (use --force to replace)", target)
243		} else if !os.IsNotExist(err) {
244			return fmt.Errorf("checking existing %s: %w", target, err)
245		}
246		return nil
247	}
