420	func markLocalInstallOverlay(projectRoot, pluginName string, files []string) (int, error) {
421		if projectRoot == "" {
422			return 0, nil
423		}
424	
425		ctx := context.Background()
426		topOut, err := internalgit.Command(ctx, projectRoot, "rev-parse", "--show-toplevel").Output()
427		if err != nil {
428			return 0, nil
429		}
430		repoRoot := strings.TrimSpace(string(topOut))
431		if repoRoot == "" {
432			return 0, nil
433		}
434	
435		paths := localOverlayPaths(pluginName, files)
436		if len(paths) == 0 {
437			return 0, nil
438		}
439		if err := addLocalOverlayIgnores(repoRoot, paths); err != nil {
440			return 0, err
441		}
442	
443		args := append([]string{"ls-files", "-z", "--"}, paths...)
444		trackedOut, err := internalgit.Command(ctx, repoRoot, args...).Output()
445		if err != nil {
446			return 0, err
447		}
448		var tracked []string
449		for _, p := range strings.Split(string(trackedOut), "\x00") {
450			if p != "" {
451				tracked = append(tracked, p)
452			}
453		}
454		for start := 0; start < len(tracked); start += 100 {
455			end := start + 100
456			if end > len(tracked) {
457				end = len(tracked)
458			}
459			args := append([]string{"update-index", "--skip-worktree", "--"}, tracked[start:end]...)
460			if err := internalgit.Command(ctx, repoRoot, args...).Run(); err != nil {
461				return 0, err
462			}
463		}
464		return len(tracked), nil
465	}
