589	func loadLocalPluginManifestPackage(root, expectedName string) (*registry.Package, bool, error) {
590		for _, rel := range []string{
591			filepath.Join(".codex-plugin", "plugin.json"),
592			filepath.Join(".claude-plugin", "plugin.json"),
593		} {
594			path := filepath.Join(root, rel)
595			data, err := os.ReadFile(path)
596			if os.IsNotExist(err) {
597				continue
598			}
599			if err != nil {
600				return nil, false, fmt.Errorf("loading plugin manifest %s: %w", path, err)
601			}
602			var manifest localPluginJSONManifest
603			if err := json.Unmarshal(data, &manifest); err != nil {
604				return nil, false, fmt.Errorf("loading plugin manifest %s: invalid JSON: %w", path, err)
605			}
606			name := strings.TrimSpace(manifest.Name)
607			if name == "" {
608				name = expectedName
609			}
610			if name != expectedName {
611				return nil, false, fmt.Errorf("local package name %q does not match plugin manifest name %q", expectedName, name)
612			}
613			sources, err := pluginManifestSkillSources(manifest.Skills)
614			if err != nil {
615				return nil, false, fmt.Errorf("loading plugin manifest %s: %w", path, err)
616			}
617			pkg := &registry.Package{
618				Name:        name,
619				Version:     defaultString(strings.TrimSpace(manifest.Version), "local"),
620				Description: defaultString(strings.TrimSpace(manifest.Description), "local plugin package"),
621				Type:        registry.PackageTypePlugin,
622				Source:      defaultString(strings.TrimSpace(manifest.Repository), root),
623				Install: registry.PackageInstall{
624					Root: &registry.InstallMapping{
625						Source: ".",
626						Target: fmt.Sprintf(".ddx/plugins/%s", name),
627					},
628				},
629			}
630			for _, source := range sources {
631				pkg.Install.Skills = append(pkg.Install.Skills, registry.InstallMapping{
632					Source: source,
633					Target: ".agents/skills/",
634				})
635			}
636			return pkg, true, nil
637		}
638		return nil, false, nil
639	}
