799	func localInstallPathAliases(path string) []string {
800		seen := map[string]bool{}
801		var aliases []string
802		add := func(candidate string) {
803			if strings.TrimSpace(candidate) == "" {
804				return
805			}
806			abs, err := filepath.Abs(candidate)
807			if err != nil {
808				abs = candidate
809			}
810			if !seen[abs] {
811				seen[abs] = true
812				aliases = append(aliases, abs)
813			}
814		}
815		add(path)
816		if resolved, err := filepath.EvalSymlinks(path); err == nil && resolved != "" {
817			add(resolved)
818		}
819		dir := filepath.Dir(path)
820		base := filepath.Base(path)
821		if resolvedDir, err := filepath.EvalSymlinks(dir); err == nil && resolvedDir != "" {
822			add(filepath.Join(resolvedDir, base))
823		}
824		return aliases
825	}
