944	func (f *CommandFactory) runVerify(cmd *cobra.Command, args []string) error {
945		out := cmd.OutOrStdout()
946	
947		state, err := registry.LoadState()
948		if err != nil {
949			return fmt.Errorf("loading state: %w", err)
950		}
951	
952		if len(state.Installed) == 0 {
953			fmt.Fprintln(out, "No packages installed.")
954			return nil
955		}
956	
957		var totalIssues int
958		for _, entry := range state.Installed {
959			var issues []string
960			for _, f := range entry.Files {
961				expanded := registry.ExpandHome(f)
962				info, err := os.Lstat(expanded)
963				if os.IsNotExist(err) {
964					issues = append(issues, fmt.Sprintf("  missing: %s", f))
965					continue
966				}
967				if err != nil {
968					issues = append(issues, fmt.Sprintf("  error: %s: %v", f, err))
969					continue
970				}
971				// Check symlinks resolve.
972				if info.Mode()&os.ModeSymlink != 0 {
973					target, err := os.Readlink(expanded)
974					if err != nil {
975						issues = append(issues, fmt.Sprintf("  broken symlink: %s", f))
976						continue
977					}
978					// Resolve relative symlinks against their parent directory.
979					if !filepath.IsAbs(target) {
980						target = filepath.Join(filepath.Dir(expanded), target)
981					}
982					if _, err := os.Stat(target); os.IsNotExist(err) {
983						issues = append(issues, fmt.Sprintf("  broken symlink: %s -> %s", f, target))
984					}
985				}
986			}
987	
988			if len(issues) == 0 {
989				fmt.Fprintf(out, "%s %s: OK (%d files)\n", entry.Name, entry.Version, len(entry.Files))
990			} else {
991				fmt.Fprintf(out, "%s %s: %d issue(s)\n", entry.Name, entry.Version, len(issues))
992				for _, issue := range issues {
993					fmt.Fprintln(out, issue)
994				}
995				totalIssues += len(issues)
996			}
997		}
998	
999		if totalIssues > 0 {
1000			return fmt.Errorf("%d integrity issue(s) found — run 'ddx install <name> --force' to repair", totalIssues)
1001		}
1002		return nil
1003	}
